#!/usr/bin/env python3
# -*- coding: utf-8 -*-
from pathlib import Path
import argparse, base64, html, json, re, unicodedata
ROOT=Path(__file__).resolve().parent; BOOKS=ROOT/'books'; OUT=ROOT/'index.html'
TR={'а':'a','б':'b','в':'v','г':'h','ґ':'g','д':'d','е':'e','є':'ie','ж':'zh','з':'z','и':'y','і':'i','ї':'i','й':'i','к':'k','л':'l','м':'m','н':'n','о':'o','п':'p','р':'r','с':'s','т':'t','у':'u','ф':'f','х':'kh','ц':'ts','ч':'ch','ш':'sh','щ':'shch','ь':'','ю':'iu','я':'ia','ы':'y','э':'e','ъ':'','ё':'yo'}
def slug(s):
    s=''.join(TR.get(c,c) for c in s.lower()); s=unicodedata.normalize('NFKD',s); s=''.join(c for c in s if not unicodedata.combining(c)); return re.sub(r'[^a-z0-9]+','-',s).strip('-') or 'book'
def cover_data_url(pdf, zoom=2.0):
    try:
        import fitz, io
        from PIL import Image
        doc=fitz.open(str(pdf)); page=doc.load_page(0); r=page.rect
        clip=fitz.Rect(r.x0+r.width/2, r.y0, r.x1, r.y1)
        pix=page.get_pixmap(matrix=fitz.Matrix(zoom,zoom), clip=clip, alpha=False)
        img=Image.frombytes('RGB',[pix.width,pix.height],pix.samples)
        target=2/3; w,h=img.size
        if w/h>target:
            nw=int(h*target); left=max(0,(w-nw)//2); img=img.crop((left,0,left+nw,h))
        if img.width>720:
            nh=int(img.height*(720/img.width)); img=img.resize((720,nh), Image.LANCZOS)
        buf=io.BytesIO(); img.save(buf,format='JPEG',quality=88,optimize=True)
        return 'data:image/jpeg;base64,'+base64.b64encode(buf.getvalue()).decode('ascii')
    except Exception as e:
        print('Cover skipped for', pdf.name, ':', e); return ''
def build_books(author,category,zoom):
    BOOKS.mkdir(exist_ok=True); used=set(); out=[]; covers=0
    for pdf in sorted(BOOKS.glob('*.pdf'), key=lambda p:p.name.lower()):
        title=pdf.stem.strip(); base=slug(title); ident=base; i=2
        while ident in used: ident=f'{base}-{i}'; i+=1
        used.add(ident); cov=cover_data_url(pdf,zoom); covers+=1 if cov else 0
        out.append({'id':ident,'title':title,'author':author,'category':category,'file':'books/'+pdf.name,'cover':cov,'tags':[]})
    return out,covers
def make_html(title,books):
    data=json.dumps(books,ensure_ascii=False,separators=(',',':')).replace('</','<\\/'); t=html.escape(title)
    return f'''<!doctype html><html lang="uk"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="theme-color" content="#0f172a"><title>{t}</title><script src="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.10.38/pdf.min.mjs" type="module"></script><style>
:root{{--panel:rgba(15,23,42,.78);--text:#e5edf8;--muted:#9fb0c7;--line:rgba(255,255,255,.12);--gold:#facc15;--shadow:0 24px 80px rgba(0,0,0,.4)}}*{{box-sizing:border-box}}body{{margin:0;font-family:Inter,ui-sans-serif,system-ui,-apple-system,"Segoe UI",Arial,sans-serif;color:var(--text);background:radial-gradient(circle at 10% 0,rgba(56,189,248,.25),transparent 30%),radial-gradient(circle at 90% 0,rgba(250,204,21,.18),transparent 27%),linear-gradient(145deg,#050914,#07111f 55%,#111827);min-height:100vh}}body:before{{content:"";position:fixed;inset:0;background-image:linear-gradient(rgba(255,255,255,.035) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.035) 1px,transparent 1px);background-size:44px 44px;mask-image:linear-gradient(to bottom,black,transparent 78%);pointer-events:none}}.app{{position:relative;z-index:1}}.glass{{background:var(--panel);border:1px solid var(--line);border-radius:30px;box-shadow:var(--shadow);backdrop-filter:blur(18px)}}.hero{{padding:34px clamp(18px,4vw,58px) 18px;display:grid;grid-template-columns:1.1fr .9fr;gap:28px;align-items:center}}.heroCard{{padding:32px}}.eyebrow{{display:inline-flex;color:#fde68a;background:rgba(250,204,21,.10);border:1px solid rgba(250,204,21,.22);border-radius:999px;padding:8px 12px;font-weight:800;font-size:13px}}h1{{font-size:clamp(34px,6vw,72px);line-height:.95;margin:18px 0 14px;letter-spacing:-.06em}}.lead{{color:var(--muted);font-size:18px;line-height:1.6}}.stats{{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-top:22px}}.stat{{padding:16px;border-radius:22px;background:rgba(255,255,255,.06);border:1px solid var(--line)}}.stat b{{display:block;font-size:28px}}.stat span{{color:var(--muted);font-size:13px}}.shelf{{min-height:320px;display:flex;align-items:center;justify-content:center;overflow:hidden}}.mock{{width:180px;height:270px;border-radius:18px;box-shadow:0 30px 80px rgba(0,0,0,.46);background:linear-gradient(135deg,#fde68a,#f59e0b 50%,#7c2d12);transform:rotate(-8deg)}}.mock:nth-child(2){{background:linear-gradient(135deg,#7dd3fc,#2563eb 58%,#0f172a);transform:rotate(5deg) translate(-40px,25px)}}.mock:nth-child(3){{background:linear-gradient(135deg,#86efac,#16a34a 55%,#052e16);transform:rotate(13deg) translate(-85px,-10px)}}.toolbar{{margin:0 clamp(18px,4vw,58px) 18px;padding:16px;display:flex;gap:12px;align-items:center;justify-content:space-between;flex-wrap:wrap}}input,select,button{{font:inherit;color:var(--text);background:rgba(2,6,23,.62);border:1px solid var(--line);border-radius:16px;padding:12px 14px;outline:none}}input{{flex:1;min-width:250px}}button{{cursor:pointer}}button:hover{{background:rgba(255,255,255,.10)}}.library{{padding:8px clamp(18px,4vw,58px) 54px;display:grid;grid-template-columns:repeat(auto-fill,minmax(230px,1fr));gap:22px}}.card{{border-radius:28px;overflow:hidden;background:linear-gradient(180deg,rgba(30,41,59,.88),rgba(15,23,42,.88));border:1px solid var(--line);box-shadow:0 20px 60px rgba(0,0,0,.28);transition:.22s}}.card:hover{{transform:translateY(-7px);border-color:rgba(250,204,21,.35)}}.coverWrap{{height:330px;padding:18px;background:radial-gradient(circle at top,rgba(255,255,255,.16),transparent 55%)}}.cover{{width:100%;height:100%;object-fit:cover;border-radius:18px;box-shadow:0 18px 45px rgba(0,0,0,.42)}}.fallback{{height:100%;border-radius:18px;display:flex;align-items:center;justify-content:center;text-align:center;padding:22px;color:#111827;font-weight:900;font-size:22px;background:linear-gradient(135deg,#fde68a,#f59e0b)}}.body{{padding:18px}}.title{{font-weight:850;font-size:17px;line-height:1.25;min-height:43px}}.meta{{margin-top:6px;color:var(--muted);font-size:13px}}.badges{{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}}.badge{{font-size:12px;padding:6px 9px;border-radius:999px;background:rgba(255,255,255,.08);border:1px solid var(--line)}}.read{{color:#86efac;background:rgba(34,197,94,.12)}}.reading{{color:#7dd3fc;background:rgba(56,189,248,.12)}}.bar{{height:8px;background:rgba(255,255,255,.10);border-radius:99px;overflow:hidden;margin:14px 0}}.bar>i{{display:block;height:100%;background:linear-gradient(90deg,var(--gold),#fb923c)}}.actions{{display:flex;gap:8px;flex-wrap:wrap}}.primary{{background:linear-gradient(135deg,#facc15,#f97316);color:#111827;font-weight:800;border:0}}.small{{font-size:13px;padding:9px 10px}}.reader{{position:fixed;inset:0;background:rgba(2,6,23,.92);backdrop-filter:blur(18px);z-index:50;display:none;grid-template-rows:auto 1fr}}.reader.open{{display:grid}}.readerTop{{padding:14px clamp(12px,3vw,30px);display:flex;gap:12px;align-items:center;justify-content:space-between;border-bottom:1px solid var(--line);background:rgba(15,23,42,.88)}}.readerName{{display:flex;flex-direction:column;gap:2px;min-width:0}}.readerName b{{white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:55vw}}.readerName span{{color:var(--muted);font-size:13px}}.stage{{display:grid;place-items:center;padding:22px;overflow:auto}}.bookShell{{padding:22px;border-radius:28px;background:linear-gradient(90deg,#111827,#243044 48%,#07111f 50%,#243044 52%,#111827);box-shadow:0 30px 100px rgba(0,0,0,.62),inset 0 0 0 1px var(--line)}}canvas{{display:block;max-width:88vw;max-height:78vh;background:white;border-radius:10px;box-shadow:0 16px 40px rgba(0,0,0,.42)}}.empty{{grid-column:1/-1;padding:38px;text-align:center;color:var(--muted)}}@media(max-width:850px){{.hero{{grid-template-columns:1fr}}.shelf{{display:none}}.stats{{grid-template-columns:1fr 1fr}}.readerTop{{align-items:flex-start;flex-direction:column}}.readerName b{{max-width:90vw}}.bookShell{{padding:10px}}}}
</style></head><body><div class="app"><section class="hero"><div class="heroCard glass"><div class="eyebrow">PDF Library · GitHub Pages</div><h1>{t}</h1><p class="lead">Каталог PDF-книжок з кириличними назвами, автоматичними обкладинками з правої половини першої сторінки, статусами читання та вбудованим reader.</p><div class="stats"><div class="stat"><b id="total">0</b><span>книжок</span></div><div class="stat"><b id="read">0</b><span>прочитано</span></div><div class="stat"><b id="reading">0</b><span>читаю</span></div></div></div><div class="shelf glass"><div class="mock"></div><div class="mock"></div><div class="mock"></div></div></section><section class="toolbar glass"><input id="search" type="search" placeholder="Пошук…"><select id="filter"><option value="all">Усі</option><option value="read">Прочитані</option><option value="reading">Читаю</option><option value="unread">Не прочитані</option></select><button id="exportBtn">Експорт прогресу</button><button id="importBtn">Імпорт прогресу</button><input id="importFile" type="file" accept="application/json" hidden></section><main id="library" class="library"></main></div><div id="reader" class="reader"><div class="readerTop"><button id="close">← До бібліотеки</button><div class="readerName"><b id="rTitle">Книжка</b><span id="pageInfo">Сторінка —</span></div><div class="actions"><button id="prev">←</button><button id="next">→</button><button id="mark" class="primary">Позначити прочитаною</button></div></div><div class="stage"><div class="bookShell"><canvas id="pdfCanvas"></canvas></div></div></div><script type="application/json" id="booksData">{data}</script><script type="module">
import * as pdfjsLib from 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.10.38/pdf.min.mjs';pdfjsLib.GlobalWorkerOptions.workerSrc='https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.10.38/pdf.worker.min.mjs';const BOOKS=JSON.parse(document.getElementById('booksData').textContent),KEY='pdf-library-progress-v2';let progress=JSON.parse(localStorage.getItem(KEY)||'{{}}'),currentBook=null,pdfDoc=null,pageNum=1,rendering=false;const $=s=>document.querySelector(s),lib=$('#library'),canvas=$('#pdfCanvas'),ctx=canvas.getContext('2d');function p(id){{return progress[id]||(progress[id]={{status:'unread',lastPage:1}})}}function save(){{localStorage.setItem(KEY,JSON.stringify(progress,null,2));stats()}}function esc(s=''){{return s.replace(/[&<>"']/g,c=>({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}}[c]))}}function url(s){{return encodeURI(s)}}function stats(){{$('#total').textContent=BOOKS.length;$('#read').textContent=BOOKS.filter(b=>p(b.id).status==='read').length;$('#reading').textContent=BOOKS.filter(b=>p(b.id).status==='reading').length}}function render(){{let q=$('#search').value.toLowerCase().trim(),f=$('#filter').value;let items=BOOKS.filter(b=>{{let pr=p(b.id),hay=[b.title,b.author,b.category,...(b.tags||[])].join(' ').toLowerCase();return hay.includes(q)&&(f==='all'||pr.status===f)}});if(!items.length){{lib.innerHTML='<div class="empty glass">PDF не знайдено. Додай файли в папку books/ і зроби push.</div>';return}}lib.innerHTML=items.map(b=>{{let pr=p(b.id),txt={{read:'Прочитано',reading:'Читаю',unread:'Не прочитано'}}[pr.status||'unread'],pct=pr.status==='read'?100:Math.min(95,Math.max(4,(pr.lastPage||1)*2)),cover=b.cover?`<img class="cover" src="${{b.cover}}">`:`<div class="fallback">${{esc(b.title)}}</div>`;return `<article class="card"><div class="coverWrap">${{cover}}</div><div class="body"><div class="title">${{esc(b.title)}}</div><div class="meta">${{esc(b.author)}} · ${{esc(b.category)}}</div><div class="badges"><span class="badge ${{pr.status}}">${{txt}}</span><span class="badge">стор. ${{pr.lastPage||1}}</span></div><div class="bar"><i style="width:${{pct}}%"></i></div><div class="actions"><button class="primary small" data-open="${{b.id}}">Відкрити</button><button class="small" data-status="reading" data-id="${{b.id}}">Читаю</button><button class="small" data-status="read" data-id="${{b.id}}">✓ Прочитано</button></div></div></article>`}}).join('');lib.querySelectorAll('[data-open]').forEach(x=>x.onclick=()=>openBook(x.dataset.open));lib.querySelectorAll('[data-status]').forEach(x=>x.onclick=()=>{{p(x.dataset.id).status=x.dataset.status;save();render()}})}}async function openBook(id){{currentBook=BOOKS.find(b=>b.id===id);if(!currentBook)return;$('#reader').classList.add('open');$('#rTitle').textContent=currentBook.title;let pr=p(id);pageNum=pr.lastPage||1;if(pr.status==='unread')pr.status='reading';save();pdfDoc=await pdfjsLib.getDocument(url(currentBook.file)).promise;pageNum=Math.min(Math.max(1,pageNum),pdfDoc.numPages);await show(pageNum)}}async function show(num){{if(!pdfDoc||rendering)return;rendering=true;let page=await pdfDoc.getPage(num),base=page.getViewport({{scale:1}}),scale=Math.min((innerWidth*.86)/base.width,(innerHeight*.74)/base.height,1.8),vp=page.getViewport({{scale}});canvas.width=vp.width;canvas.height=vp.height;await page.render({{canvasContext:ctx,viewport:vp}}).promise;$('#pageInfo').textContent=`Сторінка ${{num}} / ${{pdfDoc.numPages}}`;p(currentBook.id).lastPage=num;save();rendering=false}}$('#prev').onclick=()=>{{if(pageNum>1)show(--pageNum)}};$('#next').onclick=()=>{{if(pdfDoc&&pageNum<pdfDoc.numPages)show(++pageNum)}};$('#mark').onclick=()=>{{if(!currentBook||!pdfDoc)return;p(currentBook.id).status='read';p(currentBook.id).lastPage=pdfDoc.numPages;save();render();alert('Книжку позначено як прочитану')}};$('#close').onclick=()=>{{$('#reader').classList.remove('open');pdfDoc=null;render()}};$('#search').oninput=render;$('#filter').onchange=render;$('#exportBtn').onclick=()=>{{let blob=new Blob([JSON.stringify(progress,null,2)],{{type:'application/json'}}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='progress.json';a.click();URL.revokeObjectURL(a.href)}};$('#importBtn').onclick=()=>$('#importFile').click();$('#importFile').onchange=async e=>{{let f=e.target.files[0];if(!f)return;progress=JSON.parse(await f.text());save();render()}};addEventListener('keydown',e=>{{if(!$('#reader').classList.contains('open'))return;if(e.key==='ArrowLeft')$('#prev').click();if(e.key==='ArrowRight')$('#next').click();if(e.key==='Escape')$('#close').click()}});addEventListener('resize',()=>{{if(pdfDoc)show(pageNum)}});stats();render();
</script></body></html>'''
def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--title',default='Моя PDF-бібліотека'); ap.add_argument('--author',default='Невідомий автор'); ap.add_argument('--category',default='Без категорії'); ap.add_argument('--cover-zoom',type=float,default=2.0); args=ap.parse_args()
    books,covers=build_books(args.author,args.category,args.cover_zoom); OUT.write_text(make_html(args.title,books),encoding='utf-8'); print(f'Готово. PDF: {len(books)}. Обкладинок: {covers}. Файл: index.html')
if __name__=='__main__': main()
